import { NextRequest, NextResponse } from "next/server"
import { createAdminClient } from "@/lib/supabase/admin"
import { requireAuth, rejectCliente, hasEmpresaAccess, empresaAccessDenied } from "@/lib/auth-guard"
import { withErrorHandler } from "@/lib/api-error-handler"

async function _handleGet(request: NextRequest) {
  try {
    const auth = await requireAuth(request, { skipTenantCheck: true })
    if (auth.response) return auth.response
    const clienteBlock = rejectCliente(auth.session)
    if (clienteBlock) return clienteBlock

    const supabase = createAdminClient()
    const { searchParams } = new URL(request.url)
    const leadId = searchParams.get("leadId")
    const id = searchParams.get("id")

    if (id) {
      // SEGURANCA: Verifica se a proposta pertence a um lead que o usuario tem acesso
      const { data, error } = await supabase
        .from("lead_propostas")
        .select("*, leads!inner(empresa_id)")
        .eq("id", id)
        .single()
      if (error) return NextResponse.json({ error: error.message }, { status: 500 })

      if (!hasEmpresaAccess(auth.session, (data as { leads?: { empresa_id?: string } }).leads?.empresa_id || null)) {
        return empresaAccessDenied()
      }
      return NextResponse.json(mapProposta(data))
    }

    // SEGURANCA: Se buscar por leadId, verifica se o lead pertence a uma empresa acessivel
    if (leadId) {
      const { data: lead, error: leadError } = await supabase.from("leads").select("empresa_id").eq("id", leadId).single()

      // Se o lead nao existe, retorna lista vazia (nao erro)
      if (leadError || !lead) {
        return NextResponse.json([])
      }

      if (!hasEmpresaAccess(auth.session, lead.empresa_id)) {
        return empresaAccessDenied()
      }
    }

    const limit = Math.min(parseInt(searchParams.get("limit") || "100"), 500)
    const offset = parseInt(searchParams.get("offset") || "0")

    let query = supabase.from("lead_propostas").select("id, lead_id, titulo, descricao, status, valor, validade_dias, criado_por, modelo_trabalho, escopo, premissas, exclusoes, cronograma, condicoes_pagamento, conversation_history, proposal_content, structured_output, created_at, updated_at").order("created_at", { ascending: false })
    if (leadId) query = query.eq("lead_id", leadId)
    query = query.range(offset, offset + limit - 1)

    const { data, error } = await query
    if (error) return NextResponse.json({ error: error.message }, { status: 500 })

    return NextResponse.json((data || []).map(mapProposta))
  } catch (err: unknown) {
    return NextResponse.json({ error: err instanceof Error ? err.message : "Unknown error" }, { status: 500 })
  }
}

async function _handlePost(request: NextRequest) {
  try {
    const auth = await requireAuth(request, { skipTenantCheck: true })
    if (auth.response) return auth.response
    const clienteBlockPost = rejectCliente(auth.session)
    if (clienteBlockPost) return clienteBlockPost

    const supabase = createAdminClient()
    const body = await request.json()

    // SEGURANCA: Verifica se o lead pertence a uma empresa acessivel
    const { data: lead } = await supabase.from("leads").select("empresa_id").eq("id", body.leadId).single()
    if (lead && !hasEmpresaAccess(auth.session, lead.empresa_id)) {
      return empresaAccessDenied()
    }

    const { data, error } = await supabase
      .from("lead_propostas")
      .insert({
        lead_id: body.leadId,
        titulo: body.nome || body.titulo,
        descricao: body.descricao || "",
        status: body.status || "Rascunho",
        valor: body.valor || 0,
        validade_dias: body.validadeDias || 30,
        criado_por: body.criadoPor || "",
        modelo_trabalho: body.modeloTrabalho || "Escopo Fechado",
        escopo: body.escopo || "",
        premissas: body.premissas || "",
        exclusoes: body.exclusoes || "",
        cronograma: body.cronograma || "",
        condicoes_pagamento: body.condicoesPagamento || "",
        conversation_history: body.conversationHistory || [],
        proposal_content: body.proposalContent || [],
      })
      .select()
      .single()
    if (error) return NextResponse.json({ error: error.message }, { status: 500 })

    await supabase.from("lead_eventos").insert({
      lead_id: body.leadId, tipo: "proposta",
      descricao: `Proposta '${body.nome || body.titulo}' criada`, autor: body.criadoPor || "",
    })
    await supabase.from("leads").update({ updated_at: new Date().toISOString() }).eq("id", body.leadId)

    return NextResponse.json(mapProposta(data))
  } catch (err: unknown) {
    return NextResponse.json({ error: err instanceof Error ? err.message : "Unknown error" }, { status: 500 })
  }
}

async function _handlePut(request: Request) {
  try {
    const auth = await requireAuth(request, { skipTenantCheck: true })
    if (auth.response) return auth.response
    const clienteBlockPut = rejectCliente(auth.session)
    if (clienteBlockPut) return clienteBlockPut

    const supabase = createAdminClient()
    const body = await request.json()
    const { id, ...fields } = body
    if (!id) return NextResponse.json({ error: "ID obrigatorio" }, { status: 400 })

    // SEGURANCA: Verifica se a proposta pertence a um lead que o usuario tem acesso
    const { data: proposta } = await supabase
      .from("lead_propostas")
      .select("lead_id, leads!inner(empresa_id)")
      .eq("id", id)
      .single()

    if (proposta && !hasEmpresaAccess(auth.session, (proposta as { leads?: { empresa_id?: string } }).leads?.empresa_id || null)) {
      return empresaAccessDenied()
    }

    const updates: Record<string, unknown> = { updated_at: new Date().toISOString() }
    if (fields.nome !== undefined || fields.titulo !== undefined) updates.titulo = fields.nome || fields.titulo
    if (fields.descricao !== undefined) updates.descricao = fields.descricao
    if (fields.status !== undefined) updates.status = fields.status
    if (fields.valor !== undefined) updates.valor = fields.valor
    if (fields.validadeDias !== undefined) updates.validade_dias = fields.validadeDias
    if (fields.modeloTrabalho !== undefined) updates.modelo_trabalho = fields.modeloTrabalho
    if (fields.escopo !== undefined) updates.escopo = fields.escopo
    if (fields.premissas !== undefined) updates.premissas = fields.premissas
    if (fields.exclusoes !== undefined) updates.exclusoes = fields.exclusoes
    if (fields.cronograma !== undefined) updates.cronograma = fields.cronograma
    if (fields.condicoesPagamento !== undefined) updates.condicoes_pagamento = fields.condicoesPagamento
    if (fields.conversationHistory !== undefined) updates.conversation_history = fields.conversationHistory
    if (fields.proposalContent !== undefined) updates.proposal_content = fields.proposalContent
    if (fields.structuredOutput !== undefined) updates.structured_output = fields.structuredOutput

    const { error } = await supabase.from("lead_propostas").update(updates).eq("id", id)
    if (error) return NextResponse.json({ error: error.message }, { status: 500 })

    return NextResponse.json({ success: true })
  } catch (err: unknown) {
    return NextResponse.json({ error: err instanceof Error ? err.message : "Unknown error" }, { status: 500 })
  }
}

async function _handleDelete(request: NextRequest) {
  try {
    const auth = await requireAuth(request, { skipTenantCheck: true })
    if (auth.response) return auth.response
    const clienteBlockDelete = rejectCliente(auth.session)
    if (clienteBlockDelete) return clienteBlockDelete

    const supabase = createAdminClient()
    const { searchParams } = new URL(request.url)
    const id = searchParams.get("id")
    if (!id) return NextResponse.json({ error: "ID obrigatorio" }, { status: 400 })

    // SEGURANCA: Verifica se a proposta pertence a um lead que o usuario tem acesso
    const { data: proposta } = await supabase
      .from("lead_propostas")
      .select("lead_id, leads!inner(empresa_id)")
      .eq("id", id)
      .single()

    if (proposta && !hasEmpresaAccess(auth.session, (proposta as { leads?: { empresa_id?: string } }).leads?.empresa_id || null)) {
      return empresaAccessDenied()
    }

    const { error } = await supabase.from("lead_propostas").delete().eq("id", id)
    if (error) return NextResponse.json({ error: error.message }, { status: 500 })

    return NextResponse.json({ success: true })
  } catch (err: unknown) {
    return NextResponse.json({ error: err instanceof Error ? err.message : "Unknown error" }, { status: 500 })
  }
}

function mapProposta(p: Record<string, unknown>) {
  return {
    id: p.id,
    leadId: p.lead_id,
    nome: p.titulo,
    descricao: p.descricao,
    status: p.status,
    valor: Number(p.valor),
    validadeDias: p.validade_dias,
    criadoPor: p.criado_por,
    modeloTrabalho: p.modelo_trabalho,
    escopo: p.escopo,
    premissas: p.premissas,
    exclusoes: p.exclusoes,
    cronograma: p.cronograma,
    condicoesPagamento: p.condicoes_pagamento,
    conversationHistory: Array.isArray(p.conversation_history) ? p.conversation_history : [],
    proposalContent: Array.isArray(p.proposal_content) ? p.proposal_content : [],
    structuredOutput: p.structured_output ?? null,
    dataCriacao: new Date(p.created_at as string).getTime(),
    dataAtualizacao: new Date(p.updated_at as string).getTime(),
  }
}
export const GET = withErrorHandler(_handleGet, "/api/leads/propostas")
export const POST = withErrorHandler(_handlePost, "/api/leads/propostas")
export const PUT = withErrorHandler(_handlePut, "/api/leads/propostas")
export const DELETE = withErrorHandler(_handleDelete, "/api/leads/propostas")

"use client"

import { useState, useRef } from "react"
import { Download, Loader2, FileText, CheckCircle, Check, Link2 } from "lucide-react"
import { toast } from "sonner"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { cn } from "@/lib/utils"
import { MarkdownRenderer } from "@/components/markdown-renderer"
import type { ProposalSection, ProposalStatus, ProposalInteresse, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"
import { buildProposalTokens } from "@/lib/proposal-pdf-utils"

interface ProposalDocumentProps {
  empresa: string
  para?: string
  projeto?: string
  proposalNumber: string
  dataCriacao: number
  sections: ProposalSection[]
  highlightedSections: Set<string>
  status: ProposalStatus
  interesse?: ProposalInteresse
  modeloTrabalho?: ProposalModelo
  projetoGeradoId?: string
  projetoGeradoNome?: string
  onMarkConcluida?: () => void
  onAprovar?: () => void
}

export function ProposalDocument({
  empresa,
  para,
  projeto,
  proposalNumber,
  dataCriacao,
  sections,
  highlightedSections,
  status,
  interesse,
  modeloTrabalho,
  projetoGeradoId,
  projetoGeradoNome,
  onMarkConcluida,
  onAprovar,
}: ProposalDocumentProps) {
  const [downloading, setDownloading] = useState(false)
  const [approveOpen, setApproveOpen] = useState(false)
  const documentRef = useRef<HTMLDivElement>(null)

  async function handleDownloadPDF() {
    if (sections.length === 0) return
    setDownloading(true)
    try {
      // 1. Busca o novo template finalizado
      const res = await fetch("/proposta-template.html")
      if (!res.ok) throw new Error("Template não encontrado")
      let html = await res.text()

      // 2. Constrói os tokens com o novo sistema de mapeamento
      const tokens = buildProposalTokens({ empresa, para, projeto, modeloTrabalho, dataCriacao, sections })

      // 3. Substitui todas as variáveis no HTML
      for (const [key, value] of Object.entries(tokens)) {
        html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value || '')
      }

      // 4. Remove variáveis não utilizadas (novo sistema de limpeza)
      html = html.replace(/\{\{[A-Z_]+\}\}/g, '')

      // 5. Abre em nova janela e dispara impressão automaticamente
      const win = window.open("", "_blank")
      if (!win) {
        toast.error("Pop-up bloqueado. Permita pop-ups para este site e tente novamente.")
        return
      }
      win.document.open()
      win.document.write(html)
      win.document.close()

      // Aguarda carregamento completo antes de imprimir
      win.addEventListener("load", () => win.print())
      setTimeout(() => { if (win && !win.closed) win.print() }, 800)

      toast.success("Proposta aberta! Selecione 'Salvar como PDF' com margens 'Nenhuma'.")
    } catch (err) {
      console.error("[ProposalDocument] PDF error:", err)
      toast.error("Erro ao gerar o PDF.")
    } finally {
      setDownloading(false)
    }
  }

  function getStatusBadge() {
    switch (status) {
      case "Aprovada":
        return <Badge variant="default">Aprovada</Badge>
      case "Concluída":
        return <Badge variant="secondary" className="bg-green-100 text-green-700 hover:bg-green-100">Concluída</Badge>
      case "Rascunho":
      default:
        return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 hover:bg-yellow-50">Rascunho</Badge>
    }
  }

  return (
    <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-2 border-b border-border px-4 py-3">
        <div className="flex items-center gap-2">
          <h2 className="text-sm font-semibold text-foreground">Proposta Comercial</h2>
          {sections.length > 0 && getStatusBadge()}
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleDownloadPDF}
            disabled={downloading || sections.length === 0}
            className="text-primary border-primary/30 hover:bg-secondary"
          >
            {downloading ? (
              <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
            ) : (
              <Download className="mr-1.5 h-3.5 w-3.5" />
            )}
            Imprimir / Salvar PDF
          </Button>
          {/* Mark as Concluida - visible when Rascunho and has content */}
          {status === "Rascunho" && sections.length > 0 && onMarkConcluida && (
            <Button
              variant="outline"
              size="sm"
              onClick={onMarkConcluida}
              className="border-[#16a34a]/30 text-[#16a34a] hover:bg-[#dcfce7]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Marcar como Concluída
            </Button>
          )}
          {/* Aprovar Proposta - visible when Concluída */}
          {status === "Concluída" && onAprovar && (
            <Button
              size="sm"
              onClick={() => setApproveOpen(true)}
              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Aprovar Proposta
            </Button>
          )}
        </div>
      </div>

      {/* Approved info banner */}
      {status === "Aprovada" && projetoGeradoId && (
        <div className="flex items-center gap-3 border-b border-border bg-secondary px-4 py-3">
          <Link2 className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi aprovada e gerou o projeto "}
            <strong>{`"${projetoGeradoNome || ""}"`}</strong>.{" "}
            <Link href={`/dashboard/projetos/${projetoGeradoId}`} className="font-medium underline underline-offset-2 hover:text-primary/90">
              Ver Projeto
            </Link>
          </p>
        </div>
      )}

      {/* Document content */}
      <div ref={documentRef} className="flex-1 overflow-y-auto p-4 lg:p-6">
        {sections.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6 text-center">
            <FileText className="mb-3 h-12 w-12 text-muted-foreground/40" />
            <p className="text-sm font-medium text-muted-foreground">
              A proposta sera gerada aqui conforme voce fornecer informacoes ao assistente.
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Comece a conversa ao lado!
            </p>
          </div>
        ) : (
          <div className="mx-auto max-w-[700px] rounded-lg border border-border bg-card p-4 shadow-md lg:p-8">
            {/* Document Header */}
            <div className="mb-6 border-b border-border pb-6">
              <div className="mb-4 text-center">
                <h1 className="text-base font-extrabold uppercase tracking-widest text-primary lg:text-lg">
                  PROPOSTA COMERCIAL — PROJETO SOB MEDIDA
                </h1>
                {modeloTrabalho && modeloTrabalho !== "Vazio" && (
                  <p className="mt-1.5 text-[11px] font-semibold uppercase tracking-widest text-primary/70">
                    MODELO DE CONTRATAÇÃO: {modeloTrabalho.toUpperCase()}
                  </p>
                )}
              </div>
              <div className="mx-auto mb-4 h-px w-16 bg-primary/30" />
              <div className="grid grid-cols-2 gap-x-6 gap-y-1.5">
                {[
                  ["PARA", para || "—"],
                  ["EMPRESA", empresa || "—"],
                  ["PROJETO", projeto || "—"],
                  ["DATA", formatDateShort(dataCriacao)],
                  ["VALIDADE", "30 dias"],
                  ["PROPOSTA Nº", `WA-${proposalNumber}`],
                ].map(([label, value]) => (
                  <div key={label} className="flex gap-1.5 text-xs lg:text-sm">
                    <span className="min-w-[90px] shrink-0 font-bold text-foreground">{label}:</span>
                    <span className="text-foreground/70">{value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Sections */}
            <div className="flex flex-col gap-6">
              {sections.map((section) => (
                <div
                  key={section.key}
                  className={cn(
                    "rounded-md px-3 py-2 transition-colors",
                    highlightedSections.has(section.key) && "section-highlight"
                  )}
                >
                  <h2 className="mb-3 border-b border-border/60 pb-1.5 text-sm font-bold text-primary lg:text-base">
                    {section.title}
                  </h2>
                  <MarkdownRenderer
                    content={section.content
                      .split("\n")
                      .filter((l) => {
                        const t = l.trim()
                        if (/^-{1,3}$/.test(t)) return false
                        if (/^[-*•✅❌]?\s*(PARA|EMPRESA|DATA|VALIDADE|TIPO|MODELO|PROPOSTA\s*N[ºo°]?):/i.test(t)) return false
                        return true
                      })
                      .join("\n")}
                    className="prose-h3:text-primary prose-h3:font-semibold prose-h4:text-foreground/90"
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Approve confirmation dialog */}
      <AlertDialog open={approveOpen} onOpenChange={setApproveOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <div className="mb-2 flex justify-center">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-[#dcfce7]">
                <CheckCircle className="h-6 w-6 text-[#16a34a]" />
              </div>
            </div>
            <AlertDialogTitle className="text-center">Aprovar Proposta</AlertDialogTitle>
            <AlertDialogDescription className="text-center">
              Ao aprovar esta proposta, as seguintes acoes serao realizadas automaticamente:
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="flex flex-col gap-2 rounded-lg bg-secondary/50 p-4">
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                {`Um novo projeto sera criado com o nome "${empresa}"`}
              </span>
            </div>
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                A proposta comercial sera adicionada a base de conhecimento do novo projeto
              </span>
            </div>
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                {`O status da proposta sera alterado para "Aprovada"`}
              </span>
            </div>
          </div>
          <p className="text-center text-xs text-muted-foreground">Deseja prosseguir?</p>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                setApproveOpen(false)
                onAprovar?.()
              }}
              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              Aprovar
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"

export function clean(text: string): string {
  return text.replace(/\*\*/g, "").replace(/\*/g, "").trim()
}

export function findSection(sections: ProposalSection[], ...keywords: string[]): ProposalSection | undefined {
  return sections.find((s) =>
    keywords.some((k) => s.key.toLowerCase().includes(k) || s.title.toLowerCase().includes(k))
  )
}

// ── GERAÇÃO DE HTML ESTRUTURADO ──

export function gerarFuncionalidadesHTML(content: string): string {
  const lines = content.split("\n")
  const items: string[] = []

  for (const line of lines) {
    const t = line.trim()
    // Formato: "1. **Nome** — Descrição"
    const m1 = t.match(/^(\d+)\.\s+\*\*(.+?)\*\*\s*[—–:\-]\s*(.+)$/)
    if (m1) {
      items.push(`<div class="func-item"><p><strong>${m1[1]}. ${m1[2]}</strong> - ${clean(m1[3])}</p></div>`)
      continue
    }

    // Formato: "1. Nome — Descrição"
    const m2 = t.match(/^(\d+)\.\s+(.+?)\s*[—–]\s*(.+)$/)
    if (m2) {
      items.push(`<div class="func-item"><p><strong>${m2[1]}. ${m2[2]}</strong> - ${clean(m2[3])}</p></div>`)
      continue
    }

    // Formato: "- **Nome**: Descrição"
    const m3 = t.match(/^[-*•]\s+\*\*(.+?)\*\*[:\s]+(.+)$/)
    if (m3) {
      items.push(`<div class="func-item"><p><strong>${items.length + 1}. ${m3[1]}</strong> - ${clean(m3[2])}</p></div>`)
      continue
    }
  }

  // Fallback: itens simples com bullet points
  if (!items.length) {
    content.split("\n")
      .filter((l) => /^[-*•]\s/.test(l.trim()))
      .slice(0, 8)
      .forEach((l, i) => {
        items.push(`<div class="func-item"><p><strong>${i + 1}. ${clean(l.replace(/^[-*•]\s+/, ""))}</strong></p></div>`)
      })
  }

  return items.join("\n\n")
}

export function gerarFasesHTML(content: string): string {
  const lines = content.split("\n")
  const phases: string[] = []
  let counter = 0

  for (const line of lines) {
    const t = line.trim()
    if (!t) continue

    // Formato: "Fase 1 - Nome | Prazo"
    const m1 = t.match(/^(?:Fase\s*)?(\d+)\s*[-:]\s*(.+?)\s*\|\s*(.+)$/)
    if (m1) {
      phases.push(`<div class="phase"><strong>Fase ${m1[1]}:</strong> ${clean(m1[2])} – ${clean(m1[3])}</div>`)
      continue
    }

    // Formato: "Fase 1 - Nome"
    const m2 = t.match(/^Fase\s*(\d+)\s*[-:]\s*(.+)$/)
    if (m2) {
      phases.push(`<div class="phase"><strong>Fase ${m2[1]}:</strong> ${clean(m2[2])}</div>`)
      continue
    }

    // Bullets com prazo
    if (/^[-*•]\s/.test(t) && /semana|mês|mes|dias?/i.test(t)) {
      counter++
      phases.push(`<div class="phase"><strong>Fase ${counter}:</strong> ${clean(t.replace(/^[-*•]\s+/, ""))}</div>`)
    }
  }

  return phases.join("\n") || `<div class="phase"><strong>Fase 1:</strong> A definir</div>`
}

export function gerarEntregaveisHTML(content: string): string {
  const deliverableKeywords = /protótipo|figma|documentação|código|repositório|sistema|produção|api\s|deploy|fonte/i
  const items = content
    .split("\n")
    .filter((l) => /^[-*•]\s/.test(l.trim()) && deliverableKeywords.test(l))
    .map((l) => `<li>${clean(l.replace(/^[-*•]\s+/, ""))}</li>`)

  if (items.length) {
    return `<ul>\n${items.join("\n")}\n</ul>`
  }

  // Lista padrão de entregáveis
  return `<ul>
<li>Protótipos de Alta Fidelidade (Figma).</li>
<li>Documentação Funcional.</li>
<li>Documentação Técnica.</li>
<li>Código Fonte Completo (repositório Git).</li>
<li>Sistema em Produção.</li>
</ul>`
}

