      .slice(0, 8)
      .forEach((l, i) => {
        items.push(`<div class="func-item"><p><strong>${i + 1}. ${clean(l.replace(/^[-*•]\s+/, ""))}</strong></p></div>`)
      })
  }

  return items.join("\n\n")
}

export function gerarFasesHTML(content: string): string {
  const lines = content.split("\n")
  const phases: string[] = []
  let counter = 0

  for (const line of lines) {
    const t = line.trim()
    if (!t) continue

    // Formato: "Fase 1 - Nome | Prazo"
    const m1 = t.match(/^(?:Fase\s*)?(\d+)\s*[-:]\s*(.+?)\s*\|\s*(.+)$/)
    if (m1) {
      phases.push(`<div class="phase"><strong>Fase ${m1[1]}:</strong> ${clean(m1[2])} – ${clean(m1[3])}</div>`)
      continue
    }

    // Formato: "Fase 1 - Nome"
    const m2 = t.match(/^Fase\s*(\d+)\s*[-:]\s*(.+)$/)
    if (m2) {
      phases.push(`<div class="phase"><strong>Fase ${m2[1]}:</strong> ${clean(m2[2])}</div>`)
      continue
    }

    // Bullets com prazo
    if (/^[-*•]\s/.test(t) && /semana|mês|mes|dias?/i.test(t)) {
      counter++
      phases.push(`<div class="phase"><strong>Fase ${counter}:</strong> ${clean(t.replace(/^[-*•]\s+/, ""))}</div>`)
    }
  }

  return phases.join("\n") || `<div class="phase"><strong>Fase 1:</strong> A definir</div>`
}

export function gerarEntregaveisHTML(content: string): string {
  const deliverableKeywords = /protótipo|figma|documentação|código|repositório|sistema|produção|api\s|deploy|fonte/i
  const items = content
    .split("\n")
    .filter((l) => /^[-*•]\s/.test(l.trim()) && deliverableKeywords.test(l))
    .map((l) => `<li>${clean(l.replace(/^[-*•]\s+/, ""))}</li>`)

  if (items.length) {
    return `<ul>\n${items.join("\n")}\n</ul>`
  }

  // Lista padrão de entregáveis
  return `<ul>
<li>Protótipos de Alta Fidelidade (Figma).</li>
<li>Documentação Funcional.</li>
<li>Documentação Técnica.</li>
<li>Código Fonte Completo (repositório Git).</li>
<li>Sistema em Produção.</li>
</ul>`
}

