export function gerarCondicoesPagamentoHTML(content: string): string {
  const vals = content.match(/R\$\s*[\d.,]+/g) ?? []
  const pct = content.match(/(\d+)%/g) ?? []

  const p1 = content.match(/(?:1[aª°]?\s*parcela|assinatura)[^R\n]*R\$\s*([\d.,]+)/i)
  const p2 = content.match(/(?:2[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)
  const p3 = content.match(/(?:3[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)

  const cond2m = content.match(/(\d+\s*dias?(?:\s*após[^,\n]+)?)/i)
  const cond3m = content.match(/(?:pós.homolog|entrega final|conclusão|go.live)/i)

  const parcela1 = p1 ? `R$ ${p1[1]}` : vals[0] ?? "A definir"
  const condicao2 = cond2m ? cond2m[1] : pct[1] ? `${pct[1]} na entrega parcial` : "30 dias após a assinatura"
  const parcela2 = p2 ? `R$ ${p2[1]}` : vals[1] ?? "A definir"
  const condicao3 = cond3m ? cond3m[0] : pct[2] ? `${pct[2]} na entrega final` : "Pós-homologação"
  const parcela3 = p3 ? `R$ ${p3[1]}` : vals[2] ?? "A definir"

  return `<div class="payment-condition"><strong>1ª parcela:</strong> ${parcela1} na assinatura do contrato</div>
<div class="payment-condition"><strong>2ª parcela:</strong> ${parcela2} - ${condicao2}</div>
<div class="payment-condition"><strong>3ª parcela:</strong> ${parcela3} - ${condicao3}</div>`
}

// ── FUNÇÕES DE EXTRAÇÃO (adaptadas para novo template) ──

export function extractValorTotal(content: string): string {
  const totalLine = content.split("\n").find((l) => /total/i.test(l) && /R\$/i.test(l))
  if (totalLine) {
    const m = totalLine.match(/R\$\s*[\d.,]+/)
    if (m) return `<p class="investment-total">Investimento total: ${m[0]}</p>`
  }
  const m = content.match(/R\$\s*[\d.,]+/)
  return m ? `<p class="investment-total">Investimento total: ${m[0]}</p>` : `<p class="investment-total">Investimento total: A definir</p>`
}

export function extractSubtitulo(content: string, projeto: string): string {
  if (projeto) return projeto
  const h3 = content.match(/^###\s+(.+)$/m)
  if (h3) return clean(h3[1])
  const bold = content.match(/\*\*(.+?)\*\*/)
  if (bold) return bold[1]
  return clean(content.split("\n").find((l) => l.trim()) ?? "Projeto")
}

export function extractDescricao(content: string): string {
  const lines = content.split("\n")
  const paragrafos = lines.filter((l) => {
    const t = l.trim()
    return t && !t.startsWith("#") && !t.startsWith("-") && !t.startsWith("*") && !/^\d+\./.test(t)
  }).map(l => `<p>${clean(l)}</p>`)

  return paragrafos.length > 0 ? paragrafos.join("\n") : "<p>Projeto desenvolvido sob medida para atender às necessidades específicas do cliente.</p>"
}

export function extractPrazoTotal(content: string): string {
  const m1 = content.match(/(?:prazo|total|estimado)[:\s]+(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?|dias?))/i)
  if (m1) return `<p><strong>Prazo total:</strong> ${m1[1]}</p>`
  const m2 = content.match(/(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?))/i)
  if (m2) return `<p><strong>Prazo total:</strong> ${m2[1]}</p>`
  return "<p><strong>Prazo total:</strong> A definir</p>"
}

