export function buildProposalTokens(params: {
  empresa: string
  para: string | undefined
  projeto: string | undefined
  modeloTrabalho: ProposalModelo | undefined
  dataCriacao: number
  sections: ProposalSection[]
}): Record<string, string> {
  const { empresa, para, projeto, modeloTrabalho, dataCriacao, sections } = params

  // Buscar seções relevantes com mais flexibilidade
  const sobreSection     = findSection(sections, "sobre", "projeto", "objetivo", "descrição")
  const funcionalidadesSection = findSection(sections, "funcionalidade", "funcionalidades", "features", "requisito")
  const integracoesSection = findSection(sections, "integra", "integrações", "previstas")
  const modeloSection    = findSection(sections, "modelo", "trabalho", "escopo", "metodologia")
  const equipeSection    = findSection(sections, "equipe", "team", "especialistas", "multidisciplinar")
  const cronoSection     = findSection(sections, "cronograma", "prazo", "timeline", "semanas", "fases")
  const investSection    = findSection(sections, "investimento", "valor", "preço", "total", "precificação")
  const condicoesSection = findSection(sections, "condições", "pagamento", "parcela", "financeiro")
  const entregaSection   = findSection(sections, "entregáveis", "entrega", "deliverable", "protótipos")

  const sobreContent         = sobreSection?.content ?? ""
  const funcionalidadesContent = funcionalidadesSection?.content ?? ""
  const integracoesContent   = integracoesSection?.content ?? ""
  const modeloContent        = modeloSection?.content ?? ""
  const equipeContent        = equipeSection?.content ?? ""
  const cronoContent         = cronoSection?.content ?? ""
  const investContent        = investSection?.content ?? ""
  const condicoesContent     = condicoesSection?.content ?? investContent
  const entregaContent       = entregaSection?.content ?? ""

  // Mapear para as novas variáveis do template dinâmico
  return {
    // ── INFORMAÇÕES DA CAPA ──
    "NOME_CLIENTE": empresa || "—",
    "NOME_EMPRESA": "Wa Project",
    "TITULO_PROPOSTA": "Proposta Comercial",
    "DATA_PROPOSTA": formatDateShort(dataCriacao),
    "DIAS_VALIDADE": "30",
    "CLIENTE_EMPRESA": para || empresa || "—",
    "TIPO_ESCOPO": modeloTrabalho && modeloTrabalho !== "Vazio" ? modeloTrabalho : "Escopo Fechado",
    "INFORMACOES_ADICIONAIS_CAPA": "",
    "CONTEUDO_INICIAL_CAPA": "",

    // ── CONTEÚDO PRINCIPAL ──
    "TITULO_SOBRE_EMPRESA": "Sobre a Wa Project",
    "DESCRICAO_EMPRESA": extractDescricao(sobreContent) || "A Wa Project é uma software house com mais de 13 anos de experiência no desenvolvimento de soluções tecnológicas customizadas.",
    "SECAO_SERVICOS": gerarServicosHTML(),
    "TITULO_CLIENTES": "Nossos Clientes",
    "LISTA_CLIENTES": gerarListaClientesHTML(),
    "INFORMACOES_ADICIONAIS_EMPRESA": "",

    // ── PROJETO E FUNCIONALIDADES ──
    "TITULO_PROJETO": "Sobre o Projeto",
    "SUBTITULO_PROJETO": extractSubtitulo(sobreContent, projeto ?? "") || "Projeto Personalizado",
    "DESCRICAO_PROJETO": extractDescricao(sobreContent) || "<p>Projeto desenvolvido sob medida para atender às necessidades específicas do cliente.</p>",
    "TITULO_FUNCIONALIDADES": "Funcionalidades",
    "LISTA_FUNCIONALIDADES": gerarFuncionalidadesHTML(funcionalidadesContent || sobreContent),
    "FUNCIONALIDADES_ADICIONAIS": "",

    // ── INTEGRAÇÕES ──
    "TITULO_INTEGRACOES": "Integrações",
    "DESCRICAO_INTEGRACOES": extractDescricao(integracoesContent) || "<p>As integrações necessárias serão implementadas conforme especificações técnicas do projeto.</p>",

    // ── MODELO DE TRABALHO ──
    "TITULO_MODELO_TRABALHO": "Modelo de Trabalho",
    "DESCRICAO_MODELO": extractDescricao(modeloContent) || `<p>Utilizamos metodologia ágil com entregas incrementais, garantindo transparência e qualidade em cada etapa do desenvolvimento.</p>`,
    "TITULO_FASES": "Fases do Projeto",
    "LISTA_FASES": gerarFasesHTML(modeloContent || cronoContent),

    // ── EQUIPE ──
    "TITULO_EQUIPE": "Equipe",
    "DESCRICAO_EQUIPE": extractDescricao(equipeContent) || `<p>O projeto contará com uma equipe multidisciplinar de especialistas:</p>`,
    "LISTA_MEMBROS_EQUIPE": equipeContent ? extractDescricao(equipeContent) : `<div class="team-role">
<h4>UX e UI Designer</h4>
<p>Responsável pelo design de interfaces, prototipagem navegável e validação de usabilidade. Cria o design system e acompanha a implementação para garantir fidelidade ao design aprovado.</p>
</div>
<div class="team-role">
<h4>Desenvolvedor(es)</h4>
<p>Realiza a implementação técnica completa (frontend e backend), integrações com APIs e sistemas externos. Garante qualidade através de testes, code review e boas práticas de desenvolvimento.</p>
</div>
<div class="team-role">
<h4>Product Owner</h4>
<p>Atua como ponte entre cliente e equipe técnica, gerenciando backlog e priorização. Garante alinhamento estratégico, planeja sprints e acompanha prazos e entregas do projeto.</p>
